,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Prc_DatosUsuario'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    vnombre VARCHAR2(30);',
'    vpapellido VARCHAR2(30);',
'    vsapellido VARCHAR2(30);',
'    vtipocedula VARCHAR2(20);',
'    vcedula VARCHAR2(30);',
'    vcorreo VARCHAR2(60);',
'    vtelefono VARCHAR2(60);',
'    vperfil VARCHAR2(30);',
'    ',
'    cursor c_datosUsuario is',
'        SELECT NOMBRE, PAPELLIDO, SAPELLIDO, TIPO_CEDULA, CEDULA, CORREO, TELEFONO, PERFIL from USUARIOS_GESTION where UPPER(usuario) = :APP_USER;',
'begin',
'    open c_datosUsuario;',
'    fetch c_datosUsuario into vnombre, vpapellido, vsapellido, vtipocedula, vcedula, vcorreo, vtelefono, vperfil;',
'    close c_datosUsuario;',
'   ',
'   :P3_NOMBRE := vnombre;',
'   :P3_PAPELLIDO := vpapellido;',
'   :P3_SAPELLIDO := vsapellido;',
'   :P3_TIPO_CEDULA := vtipocedula;',
'   :P3_CEDULA := vcedula;',
'   :P3_CORREO := vcorreo;',
'   :P3_TELEFONO := vtelefono;',
'   :P3_USUARIO := :APP_USER;',
'   :P3_PERFIL := vperfil;',
'   ',
'end;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
end;
