wwv_flow_api.create_page_da_action(
 p_id=>wwv_flow_api.id(271506847768239208)
,p_event_id=>wwv_flow_api.id(271506786650239207)
,p_event_result=>'TRUE'
,p_action_sequence=>30
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  CURSOR c_empleados IS',
'    SELECT CODIGO_EMPLEADO, NOMBRE_EMPLEADO, APELLIDO1, APELLIDO2, CEDULA, CORREO_ELECTRONICO, TELEFONO',
'    FROM EMPLEADOS@CONSULTA_ICT WHERE CEDULA = :P4_BUSCAR_EMPLEADO;',
'  ',
'	v_codigo_empleado NUMBER;',
'	v_nombre_empleado VARCHAR2(255);',
'	v_apellido1 VARCHAR2(255);',
'	v_apellido2 VARCHAR2(255);',
'	v_cedula VARCHAR2(255);',
'	v_correo_electronico VARCHAR2(255);',
'	v_telefono NUMBER(8,0);',
'  ',
'BEGIN',
'  OPEN c_empleados;',
'  LOOP',
'    FETCH c_empleados INTO v_codigo_empleado, v_nombre_empleado, v_apellido1, v_apellido2, v_cedula, v_correo_electronico, v_telefono;',
'    EXIT WHEN c_empleados%NOTFOUND;',
'    ',
'    :P4_CODIGO_EMPLEADO := v_codigo_empleado;',
'    :P4_NOMBRE := v_nombre_empleado;',
'    :P4_PAPELLIDO := v_apellido1;',
'    :P4_SAPELLIDO := v_apellido2;',
'    :P4_CEDULA := v_cedula;',
'    :P4_CORREO := v_correo_electronico;',
'    :P4_TELEFONO := v_telefono;',
'    ',
'    END LOOP;',
'  CLOSE c_empleados;',
'END;'))
,p_attribute_02=>'P4_BUSCAR_EMPLEADO'
