 p_id=>wwv_flow_api.id(291496578463830116)
,p_plug_name=>unistr('Tabla: Mis Declaratorias Tur\00EDsticas')
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(36404937346894372)
,p_plug_display_sequence=>30
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'	e.id_empresa,',
'	dt.id_declaratoria,',
'	e.nombre_solicitante,',
'    e.cedula,',
'	e.tipo_cedula,',
'	e.razon_social,',
'	e.nombre_comercial,',
'	e.telefono,',
'	e.correo,',
'	e.id_provincia,',
'	dt.fecha_registro,',
'	dt.estadodt',
'FROM empresa e',
'	INNER JOIN declaratoria_turistica dt ON e.id_empresa = dt.id_empresa     ',
'	WHERE dt.id_analista = PKG_USUARIOS.f_consulta_usuario(:APP_USER)',
'	OR dt.ID_INSPECTOR = PKG_USUARIOS.f_consulta_usuario(:APP_USER)',
'    ORDER BY dt.id_declaratoria DESC'))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_units=>'MILLIMETERS'
