wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(255516181597615130)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_DENEGAR_DT'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_numero_oficio VARCHAR2(255);',
'    v_error_message VARCHAR2(4000);',
'    ',
'BEGIN',
unistr('    -- 1. Obtener n\00FAmero de oficio'),
'    BEGIN',
'        v_numero_oficio := PKG_DECLARATORIA.f_obtener_max_oficio_jefe(:P8_ID_DECLARATORIA);',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
unistr('            -- Si no se encuentra, asignamos NULL o manejamos seg\00FAn la l\00F3gica de negocio'),
'            v_numero_oficio := NULL;',
'        WHEN OTHERS THEN',
unistr('            v_error_message := ''Error OFI-DEN-001 al obtener el n\00FAmero de oficio para denegaci\00F3n: '' || SQLERRM;'),
'            ',
'            -- Mostrar error y detener el proceso',
'            APEX_ERROR.ADD_ERROR (',
'                p_message => v_error_message,',
'                p_display_location => APEX_ERROR.C_ON_ERROR_PAGE ',
'            );',
unistr('            RAISE; -- Re-lanza la excepci\00F3n'),
'    END;',
'',
'    -- 2. Actualizar estado a 7 (DENEGADA)',
'    PKG_DECLARATORIA.sp_actualizar_estado(:P8_ID_DECLARATORIA, 7);',
'    ',
'    -- 3. Enviar correo',
'    PKG_CORREOS.sp_enviar_correo_html_adj(',
'        p_destinatario_in => :P8_CORREO,',
'        p_cc_in => NULL,',
'        p_id_mensaje => 3,',
'        p_parametros => ''ID_DECLARATORIA='' || :P8_ID_DECLARATORIA || ',
'                        '',ESTADO=DENEGADA'',',
'        p_num_oficio => v_numero_oficio',
'    );',
'',
unistr('    -- Mensaje de \00E9xito espec\00EDfico para la denegaci\00F3n'),
unistr('    APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := ''\D83D\DED1 La declaratoria tur\00EDstica ha sido DENEGADA con \00E9xito.'';'),
'    ',
'EXCEPTION',
'    -- Manejador general para cualquier error que ocurra en el paso 2 o 3',
'    WHEN OTHERS THEN',
unistr('        v_error_message := ''\274C Error INESPERADO ('' || SQLCODE || '') durante el proceso de denegaci\00F3n: '' || SQLERRM;'),
'        ',
'        -- Muestra el mensaje de error personalizado',
'        APEX_ERROR.ADD_ERROR (',
unistr('            p_message => ''Lo sentimos, ocurri\00F3 un error grave al denegar la declaratoria. Por favor, contacte a soporte. Detalle: '' || v_error_message,'),
'            p_display_location => APEX_ERROR.C_ON_ERROR_PAGE',
'        );',
'        ',
unistr('        RAISE; -- Re-lanza la excepci\00F3n para asegurar que APEX detenga la ejecuci\00F3n y revierta la transacci\00F3n'),
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'denegar_dt'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
);
