'                p_message => v_error_message,',
'                p_display_location => APEX_ERROR.C_ON_ERROR_PAGE ',
'            );',
unistr('            RAISE; -- Re-lanza la excepci\00F3n'),
'    END;',
'',
'    -- 2. Actualizar estado a 6 (APROBADA)',
'    PKG_CONTRATO.sp_actualizar_estado(:P8_ID_CONTRATO, 6);',
'    ',
'    -- 3. Enviar correo (ID 4, ESTADO=APROBADA)',
'    PKG_CORREOS.sp_enviar_correo_html_adj(',
'        p_destinatario_in => :P8_CORREO,',
'        p_cc_in => NULL,',
unistr('        p_id_mensaje => 4, -- Asumo que este ID de mensaje es espec\00EDfico para contratos'),
'        p_parametros => ''ID_CONTRATO='' || :P8_ID_CONTRATO || ',
'                        '',ESTADO=APROBADA'',',
'        p_num_oficio => v_numero_oficio',
'    );',
'',
unistr('    -- Mensaje de \00E9xito espec\00EDfico para la aprobaci\00F3n del contrato'),
unistr('    APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE := ''\2705 \00A1El contrato tur\00EDstico ha sido APROBADO con \00E9xito!'';'),
'    ',
'EXCEPTION',
'    -- Manejador general para cualquier error que ocurra en el paso 2 o 3',
'    WHEN OTHERS THEN',
unistr('        v_error_message := ''\274C Error INESPERADO ('' || SQLCODE || '') durante el proceso de aprobaci\00F3n del contrato: '' || SQLERRM;'),
'        ',
'        -- Muestra el mensaje de error personalizado',
'        APEX_ERROR.ADD_ERROR (',
unistr('            p_message => ''Lo sentimos, ocurri\00F3 un error grave al aprobar el contrato. Por favor, contacte a soporte. Detalle: '' || v_error_message,'),
'            p_display_location => APEX_ERROR.C_ON_ERROR_PAGE',
'        );',
'        ',
unistr('        RAISE; -- Re-lanza la excepci\00F3n para asegurar que APEX detenga la ejecuci\00F3n y revierta la transacci\00F3n'),
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'aprobar_ct'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
);
