,p_validation_name=>'VAL_CORREO_FORMAT'
,p_validation_sequence=>50
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_emails VARCHAR2(4000) := :P10_CORREOICT; -- Reemplaza :P10_CORREOICT con el nombre de tu item',
'  v_regex VARCHAR2(100) := ''^[A-Za-z0-9_.+-]+@[A-Za-z0-9-]+\.[A-Za-z0-9-.]+$'';',
'BEGIN',
'  FOR email IN (SELECT REGEXP_SUBSTR(v_emails, ''[^;]+'', 1, level) email FROM dual CONNECT BY LEVEL <= REGEXP_COUNT(v_emails, '';'') + 1) LOOP',
'    IF NOT REGEXP_LIKE(email.email, v_regex) THEN',
unistr('      RETURN ''Uno o m\00E1s correos electr\00F3nicos no tienen un formato v\00E1lido.'';'),
'    END IF;',
'  END LOOP;',
'  RETURN NULL;',
