wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(253019608321284134)
,p_process_sequence=>40
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_INSERTAR_ANOTACIONES_DT'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'	vArchivo BLOB;',
'	vTipoArchivo VARCHAR2(255);',
'	vNombreArchivo VARCHAR2(4000); ',
'	vMensaje_Retorno VARCHAR2(355);',
'	vRetorno boolean;',
'	vEstado NUMBER:= 0;',
'    ',
unistr('    -- L\00EDmite de caracteres impuesto para el nombre del archivo'),
'    c_limite_nombre CONSTANT NUMBER := 500; ',
'    ',
'    -- Variables para manejo de errores en APEX',
'    v_error_msg VARCHAR2(4000);',
'    v_error_code NUMBER;',
'',
'BEGIN',
'    -- **************************************************************',
unistr('    -- 1. RECUPERACI\00D3N DE ARCHIVO TEMPORAL (APEX_APPLICATION_TEMP_FILES)'),
'    -- **************************************************************',
'    SELECT',
'        BLOB_CONTENT,',
'        MIME_TYPE,',
'        FILENAME',
'    INTO',
'        vArchivo,',
'        vTipoArchivo,',
'        vNombreArchivo',
'    FROM',
'        APEX_APPLICATION_TEMP_FILES',
'    WHERE',
'        NAME = :P10_OFICIO;',
'            ',
'    -- **************************************************************',
unistr('    -- 1.5. VALIDACI\00D3N DE LONGITUD DEL NOMBRE DEL ARCHIVO'),
'    -- **************************************************************',
'    IF LENGTH(vNombreArchivo) > c_limite_nombre THEN',
unistr('        v_error_msg := ''El nombre del archivo "'' || vNombreArchivo || ''" excede el l\00EDmite de '' || c_limite_nombre || '' caracteres. Por favor, ac\00F3rtelo.'';'),
'        ',
'        -- Mostrar el error amigable',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
unistr('        -- Detener el proceso con un c\00F3digo de error espec\00EDfico'),
'        RAISE_APPLICATION_ERROR(-20002, ''Proceso detenido: Nombre de archivo demasiado largo.'');',
'    END IF;',
'    ',
'    -- **************************************************************',
unistr('    -- 2. L\00D3GICA DE PROCESAMIENTO Y ENV\00CDO DE CORREO'),
'    -- **************************************************************',
'    ',
'    IF :P10_TIPOCORREO = ''E'' THEN',
'        ',
'        vEstado := 4;',
'        ',
unistr('        -- Inserci\00F3n de anotaci\00F3n (PUBLICO)'),
'        PKG_DECLARATORIA.sp_insertar_anotacion(pnum_oficio        => :P10_NUM_OFICIO,',
'                                                poficio            => vArchivo,',
'                                                ptarchivo_oficio   => vTipoArchivo,',
'                                                pnombre_archivo    => vNombreArchivo,',
'                                                pusuario_envia     => :APP_USER,',
'                                                pid_declaratoria   => :P10_ID_DECLARATORIA,',
'                                                pid_contrato       => NULL, ',
'                                                pcorreo_receptor   => :P10_CORREO,',
'                                                ptipo_anotacion    => ''PUBLICO'',',
'                                                pmensaje_retorno   => vMensaje_Retorno,',
'                                                pretorno           => vRetorno);',
'        ',
unistr('        -- Env\00EDo de Correo'),
'        PKG_CORREOS.sp_enviar_correo_html_adj(',
'            p_destinatario_in => :P10_CORREO,',
'            p_cc_in => NULL,',
'            p_id_mensaje => 5,',
'            p_parametros => ''ID_DECLARATORIA='' || :P10_ID_DECLARATORIA || ',
'                            '',MENSAJE='' || :P10_CUERPO_CORREO,',
'                            p_num_oficio => :P10_NUM_OFICIO',
'        );',
'        ',
'    ELSE -- Correo tipo ''Interno'' o cualquier otro valor',
'    ',
'        vEstado := 5;',
'        ',
unistr('        -- Inserci\00F3n de anotaci\00F3n (PRIVADO)'),
'        PKG_DECLARATORIA.sp_insertar_anotacion(pnum_oficio        => :P10_NUM_OFICIO,',
'                                                poficio            => vArchivo,',
'                                                ptarchivo_oficio   => vTipoArchivo,',
'                                                pnombre_archivo    => vNombreArchivo,',
'                                                pusuario_envia     => :APP_USER,',
'                                                pid_declaratoria   => :P10_ID_DECLARATORIA,',
'                                                pid_contrato       => NULL, ',
'                                                pcorreo_receptor   => :P10_CORREOICT, ',
'                                                ptipo_anotacion    => ''PRIVADO'',',
'                                                pmensaje_retorno   => vMensaje_Retorno,',
'                                                pretorno           => vRetorno);',
'',
unistr('        -- Env\00EDo de Correo'),
'        PKG_CORREOS.sp_enviar_correo_html_adj(',
'            p_destinatario_in => :P10_CORREOICT,',
'            p_cc_in => NULL,',
'            p_id_mensaje => 5,',
'            p_parametros => ''ID_DECLARATORIA='' || :P10_ID_DECLARATORIA || ',
'                            '',MENSAJE='' || :P10_CUERPO_CORREO,',
'                            p_num_oficio => :P10_NUM_OFICIO',
'        );',
'    END IF;',
'    ',
unistr('    -- Actualizaci\00F3n de estado'),
'    PKG_DECLARATORIA.sp_actualizar_estado(:P10_ID_DECLARATORIA, vEstado);',
'    ',
'    -- **************************************************************',
unistr('    -- MENSAJE DE \00C9XITO'),
'    -- **************************************************************',
'    ',
'EXCEPTION',
'    -- **************************************************************',
'    -- 3. MANEJO CENTRALIZADO DE EXCEPCIONES',
'    -- **************************************************************',
'',
unistr('    -- Excepci\00F3n si el archivo temporal no existe'),
'    WHEN NO_DATA_FOUND THEN',
unistr('        v_error_msg := ''Error: No se encontr\00F3 el archivo temporal con el nombre '' || :P10_OFICIO || ''. Aseg\00FArese de que el archivo fue cargado correctamente.'';'),
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido: Archivo no encontrado.'');',
'',
unistr('    -- Excepci\00F3n si se encuentran m\00FAltiples archivos (error inesperado)'),
'    WHEN TOO_MANY_ROWS THEN',
unistr('        v_error_msg := ''Error de sistema: M\00FAltiples archivos temporales encontrados para '' || :P10_OFICIO || ''.'';'),
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
unistr('        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido: M\00FAltiples archivos encontrados.'');'),
'    ',
'    -- Manejo de errores generales, incluyendo los RAISE_APPLICATION_ERROR (-2000x)',
'    WHEN OTHERS THEN',
'        v_error_code := SQLCODE;',
'        v_error_msg := SQLERRM;',
'',
'        IF v_error_code = -20001 THEN',
'            -- Error de PKG_CORREOS',
'            v_error_msg := ''Error de Correo: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);',
'        ELSIF v_error_code = -20002 THEN',
unistr('            -- Captura el error de validaci\00F3n de longitud del nombre'),
unistr('            v_error_msg := ''Validaci\00F3n: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);'),
'        ELSIF v_error_code <= -20000 THEN',
'            -- Captura cualquier otro RAISE_APPLICATION_ERROR',
unistr('            v_error_msg := ''Error de Aplicaci\00F3n: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);'),
'        ELSE',
unistr('            -- Otros errores (conexi\00F3n, fallos de PL/SQL, etc.)'),
unistr('            v_error_msg := ''Error inesperado en el proceso de env\00EDo: '' || v_error_msg;'),
'        END IF;',
'',
'        -- Usar APEX_ERROR para mostrar el mensaje personalizado en pantalla.',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'        ',
unistr('        -- CLAVE: Lanzar una excepci\00F3n de aplicaci\00F3n gen\00E9rica para DETENER el proceso.'),
unistr('        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido debido a un error de ejecuci\00F3n.'');'),
'',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(253019431591281915)
,p_process_when=>'P10_ID_DECLARATORIA'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_process_success_message=>unistr('Oficio agregado con \00E9xito')
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(253497321587125396)
,p_process_sequence=>50
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_INSERTAR_ANOTACIONES_CT'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'	vArchivo BLOB;',
'	vTipoArchivo VARCHAR2(255);',
'	vNombreArchivo VARCHAR2(4000); -- Aumentado para soportar nombres largos',
'	vMensaje_Retorno VARCHAR2(355);',
'	vRetorno boolean;',
'	vEstado NUMBER:= 0;',
'    ',
unistr('    -- L\00EDmite de caracteres impuesto para el nombre del archivo'),
'    c_limite_nombre CONSTANT NUMBER := 500; ',
'    ',
'    -- Variables para manejo de errores en APEX',
'    v_error_msg VARCHAR2(4000);',
'    v_error_code NUMBER;',
'',
'BEGIN',
'    -- **************************************************************',
unistr('    -- 1. RECUPERACI\00D3N DE ARCHIVO TEMPORAL (APEX_APPLICATION_TEMP_FILES)'),
'    -- **************************************************************',
'    SELECT',
'        BLOB_CONTENT,',
'        MIME_TYPE,',
'        FILENAME',
'    INTO',
'        vArchivo,',
'        vTipoArchivo,',
'        vNombreArchivo',
'    FROM',
'        APEX_APPLICATION_TEMP_FILES',
'    WHERE',
'        NAME = :P10_OFICIO;',
'            ',
'    -- **************************************************************',
unistr('    -- 1.5. VALIDACI\00D3N DE LONGITUD DEL NOMBRE DEL ARCHIVO (RESTRICCI\00D3N AGREGADA)'),
'    -- **************************************************************',
'    IF LENGTH(vNombreArchivo) > c_limite_nombre THEN',
unistr('        v_error_msg := ''El nombre del archivo "'' || vNombreArchivo || ''" excede el l\00EDmite de '' || c_limite_nombre || '' caracteres. Por favor, ac\00F3rtelo.'';'),
'        ',
'        -- Mostrar el error amigable',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
unistr('        -- Detener el proceso con un c\00F3digo de error espec\00EDfico (-20002)'),
'        RAISE_APPLICATION_ERROR(-20002, ''Proceso detenido: Nombre de archivo demasiado largo.'');',
'    END IF;',
'    ',
'    -- **************************************************************',
unistr('    -- 2. L\00D3GICA DE PROCESAMIENTO Y ENV\00CDO DE CORREO'),
'    -- **************************************************************',
'    ',
'    IF :P10_TIPOCORREO = ''E'' THEN',
'        ',
'        vEstado := 4;',
'        ',
unistr('        -- Inserci\00F3n de anotaci\00F3n (PUBLICO)'),
unistr('        -- Par\00E1metros actualizados seg\00FAn la definici\00F3n de la firma:'),
'        PKG_DECLARATORIA.sp_insertar_anotacion(pnum_oficio        => :P10_NUM_OFICIO,',
'                                                poficio            => vArchivo,',
'                                                ptarchivo_oficio   => vTipoArchivo,',
'                                                pnombre_archivo    => vNombreArchivo,',
'                                                pusuario_envia     => :APP_USER,',
'                                                pid_declaratoria   => :P10_ID_DECLARATORIA,',
'                                                pid_contrato       => :P10_ID_CONTRATO, ',
'                                                pcorreo_receptor   => :P10_CORREO,',
'                                                ptipo_anotacion    => ''PUBLICO'',',
'                                                pmensaje_retorno   => vMensaje_Retorno,',
'                                                pretorno           => vRetorno);',
'        ',
unistr('        -- Env\00EDo de Correo'),
'        PKG_CORREOS.sp_enviar_correo_html_adj(',
'                    p_destinatario_in => :P10_CORREO,',
'                    p_cc_in => NULL,',
'                    p_id_mensaje => 6,',
'                    p_parametros => ''ID_CONTRATO='' || :P10_ID_CONTRATO || ',
'                                    '',MENSAJE='' || :P10_CUERPO_CORREO,',
'                    p_num_oficio => :P10_NUM_OFICIO',
'        );',
'        ',
'    ELSE -- Correo tipo ''Interno'' o cualquier otro valor',
'    ',
'        vEstado := 5;',
'        ',
unistr('        -- Inserci\00F3n de anotaci\00F3n (PRIVADO)'),
unistr('        -- Par\00E1metros actualizados seg\00FAn la definici\00F3n de la firma:'),
'        PKG_DECLARATORIA.sp_insertar_anotacion(pnum_oficio        => :P10_NUM_OFICIO,',
'                                                poficio            => vArchivo,',
'                                                ptarchivo_oficio   => vTipoArchivo,',
'                                                pnombre_archivo    => vNombreArchivo,',
'                                                pusuario_envia     => :APP_USER,',
'                                                pid_declaratoria   => :P10_ID_DECLARATORIA,',
'                                                pid_contrato       => :P10_ID_CONTRATO,',
'                                                pcorreo_receptor   => :P10_CORREOICT,',
'                                                ptipo_anotacion    => ''PRIVADO'',',
'                                                pmensaje_retorno   => vMensaje_Retorno,',
'                                                pretorno           => vRetorno);',
'',
unistr('        -- Env\00EDo de Correo'),
'        PKG_CORREOS.sp_enviar_correo_html_adj(',
'                    p_destinatario_in => :P10_CORREOICT,',
'                    p_cc_in => NULL,',
'                    p_id_mensaje => 6,',
'                    p_parametros => ''ID_CONTRATO='' || :P10_ID_CONTRATO || ',
'                                    '',MENSAJE='' || :P10_CUERPO_CORREO,',
'                    p_num_oficio => :P10_NUM_OFICIO',
'        ); ',
'    END IF;',
'    ',
unistr('    -- Actualizaci\00F3n de estado'),
'    PKG_CONTRATO.sp_actualizar_estado(:P10_ID_CONTRATO, vEstado);',
'    ',
'    -- **************************************************************',
unistr('    -- MENSAJE DE \00C9XITO'),
'    -- **************************************************************',
'    ',
'EXCEPTION',
'    -- **************************************************************',
'    -- 3. MANEJO CENTRALIZADO DE EXCEPCIONES',
'    -- **************************************************************',
'',
unistr('    -- Excepci\00F3n si el archivo temporal no existe'),
'    WHEN NO_DATA_FOUND THEN',
unistr('        v_error_msg := ''Error: No se encontr\00F3 el archivo temporal con el nombre '' || :P10_OFICIO || ''. Aseg\00FArese de que el archivo fue cargado correctamente.'';'),
'        ',
'        -- Mostrar el error amigable',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'        -- Detener el proceso',
'        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido: Archivo no encontrado.'');',
'',
unistr('    -- Excepci\00F3n si se encuentran m\00FAltiples archivos (error inesperado)'),
'    WHEN TOO_MANY_ROWS THEN',
unistr('        v_error_msg := ''Error de sistema: M\00FAltiples archivos temporales encontrados para '' || :P10_OFICIO || ''.'';'),
'        ',
'        -- Mostrar el error amigable',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'        -- Detener el proceso',
unistr('        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido: M\00FAltiples archivos encontrados.'');'),
'    ',
'    -- Manejo de errores generales, incluyendo los RAISE_APPLICATION_ERROR (-2000x)',
'    WHEN OTHERS THEN',
'        v_error_code := SQLCODE;',
'        v_error_msg := SQLERRM;',
'',
'        IF v_error_code = -20001 THEN',
'            -- Error de PKG_CORREOS',
'            v_error_msg := ''Error de Correo: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);',
'        ELSIF v_error_code = -20002 THEN',
unistr('            -- Captura el nuevo error de validaci\00F3n de longitud del nombre'),
unistr('            v_error_msg := ''Validaci\00F3n: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);'),
'        ELSIF v_error_code <= -20000 THEN',
'            -- Captura cualquier otro RAISE_APPLICATION_ERROR',
unistr('            v_error_msg := ''Error de Aplicaci\00F3n: '' || SUBSTR(v_error_msg, INSTR(v_error_msg, '':'') + 1);'),
'        ELSE',
unistr('            -- Otros errores (conexi\00F3n, fallos de PL/SQL, etc.)'),
unistr('            v_error_msg := ''Error inesperado en el proceso de env\00EDo: '' || v_error_msg;'),
'        END IF;',
'',
'        -- Usar APEX_ERROR para mostrar el mensaje personalizado en pantalla.',
'        APEX_ERROR.ADD_ERROR (',
'            p_message          => v_error_msg,',
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'        ',
unistr('        -- Lanzar una excepci\00F3n de aplicaci\00F3n gen\00E9rica para DETENER el proceso.'),
unistr('        RAISE_APPLICATION_ERROR(-20999, ''Proceso detenido debido a un error de ejecuci\00F3n.'');'),
'',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(253199168552068537)
,p_process_success_message=>unistr('Oficio agregado con \00E9xito!')
);
end;
