,p_plug_name=>unistr('Tabla: Contratos Tur\00EDsticos')
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(36404937346894372)
,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'	e.id_empresa,',
'	dt.id_declaratoria,',
'    ct.id_contrato,',
'	e.nombre_solicitante,',
'    e.cedula,',
'	e.tipo_cedula,',
'	e.razon_social,',
'	e.nombre_comercial,',
'	e.telefono,',
'	e.correo,',
'	e.id_provincia,',
'	ct.fecha_registro,',
'	ct.estadoct',
'FROM empresa e',
'	INNER JOIN declaratoria_turistica dt ON e.id_empresa = dt.id_empresa',
'    INNER JOIN contrato_turistico ct ON ct.ID_DECLARATORIA = dt.id_declaratoria',
'	WHERE ct.estadoct NOT IN (6, 7, 9, 10)'))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
