 p_id=>wwv_flow_api.id(255136292955437217)
,p_plug_name=>unistr('Datos del Contrato Tur\00EDstico')
,p_region_template_options=>'#DEFAULT#:t-Region--accent9:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(36406847262894371)
,p_plug_display_sequence=>40
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'       ROWID,',
'       ID_CONTRATO,',
'       ID_DECLARATORIA,',
'       FECHA_REGISTRO,',
'       ID_ANALISTA,',
'       FECHA_ASIG_ANALISTA,',
'       ID_INSPECTOR,',
'       FECHA_ASIG_INSPECTOR,',
'       ESTADOCT',
'FROM CONTRATO_TURISTICO ct',
'WHERE',
unistr('    ct.estadoct <> 10 -- Esta condici\00F3n debe estar fuera del OR y se aplica a todo'),
'    AND (',
'        (:P23_OPCION_FILTRO = ''1'' AND ct.estadoct = 1)',
'        OR',
'        (:P23_OPCION_FILTRO = ''2'' AND ct.estadoct NOT IN (1, 6, 7))',
'    );'))
,p_plug_source_type=>'NATIVE_IG'
,p_master_region_id=>wwv_flow_api.id(509994290841204143)
