wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(509986844121204133)
,p_plug_name=>'Datos de la Empresa'
,p_region_template_options=>'#DEFAULT#:t-Region--accent3:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(36406847262894371)
,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'    e.id_empresa,',
'    e.NOMBRE_SOLICITANTE,',
'    e.tipo_cedula,',
'    e.cedula,',
'    e.RAZON_SOCIAL,',
'    e.NOMBRE_COMERCIAL,',
'    e.TELEFONO,',
'    e.ID_PROVINCIA',
'FROM',
'    empresa e',
'    INNER JOIN declaratoria_turistica dt ON e.id_empresa = dt.id_empresa',
'    INNER JOIN contrato_turistico ct ON dt.id_declaratoria = ct.id_declaratoria',
'WHERE',
unistr('    ct.estadoct <> 10 -- Esta condici\00F3n debe estar fuera del OR y se aplica a todo'),
'    AND (',
'        (:P23_OPCION_FILTRO = ''1'' AND ct.estadoct = 1)',
'        OR',
'        (:P23_OPCION_FILTRO = ''2'' AND ct.estadoct NOT IN (1, 6, 7))',
'    );'))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P23_OPCION_FILTRO'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
