,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_analista_actual DECLARATORIA_TURISTICA.ID_ANALISTA%TYPE;',
'BEGIN',
unistr('    -- 1. Obtener el ID_ANALISTA que est\00E1 actualmente en la base de datos '),
unistr('    --    para el registro que se est\00E1 editando.'),
'    SELECT ID_ANALISTA',
'      INTO v_analista_actual',
'      FROM DECLARATORIA_TURISTICA',
'     WHERE ID_DECLARATORIA = :P34_ID_DECLARATORIA; -- Usa la clave del registro',
'     ',
'    -- 2. Comparar el valor actual de la base de datos (v_analista_actual) ',
'    --    con el nuevo valor seleccionado en el ComboBox (:P34_ID_ANALISTA)',
'    IF :P34_ID_ANALISTA = v_analista_actual THEN',
'        -- Si son iguales, devolvemos el mensaje de error.',
unistr('        RETURN ''NO es posible asignar la declaratoria tur\00EDstica al mismo analista. Seleccione un analista diferente para continuar'';'),
'    ELSE',
unistr('        -- Si son diferentes, la validaci\00F3n pasa (devolvemos NULL).'),
'        RETURN NULL;',
'    END IF;',
'',
'EXCEPTION',
unistr('    -- Manejo si la declaratoria a\00FAn no existe en la base de datos (ej. un registro nuevo)'),
'    WHEN NO_DATA_FOUND THEN',
unistr('        -- Si no encuentra la fila, la validaci\00F3n se ignora o pasa (no hay analista original para comparar).'),
'        RETURN NULL; ',
'    ',
'END;'))
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_always_execute=>'Y'
,p_validation_condition=>'P34_FLAG_ANALISTA'
