,p_validation_name=>'VALIDAR_ASIGNAR_ID_ANALISTA'
,p_validation_sequence=>30
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_analista_actual CONTRATO_TURISTICO.ID_ANALISTA%TYPE;',
'BEGIN',
unistr('    -- 1. Obtener el ID_ANALISTA que est\00E1 actualmente en la base de datos '),
unistr('    --    para el registro que se est\00E1 editando.'),
'    SELECT ID_ANALISTA',
'      INTO v_analista_actual',
'      FROM CONTRATO_TURISTICO',
'     WHERE ID_CONTRATO = :P35_ID_CONTRATO; -- Usa la clave del registro',
'     ',
'    -- 2. Comparar el valor actual de la base de datos (v_analista_actual) ',
'    --    con el nuevo valor seleccionado en el ComboBox (:P34_ID_ANALISTA)',
'    IF :P35_ID_ANALISTA = v_analista_actual THEN',
'        -- Si son iguales, devolvemos el mensaje de error.',
unistr('        RETURN ''NO es posible asignar el contrato tur\00EDstico al mismo analista. Seleccione un analista diferente para continuar'';'),
'    ELSE',
unistr('        -- Si son diferentes, la validaci\00F3n pasa (devolvemos NULL).'),
'        RETURN NULL;',
'    END IF;',
'',
'EXCEPTION',
unistr('    -- Manejo si la declaratoria a\00FAn no existe en la base de datos (ej. un registro nuevo)'),
'    WHEN NO_DATA_FOUND THEN',
unistr('        -- Si no encuentra la fila, la validaci\00F3n se ignora o pasa (no hay analista original para comparar).'),
'        RETURN NULL; ',
'    ',
'END;'))
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_always_execute=>'Y'
,p_validation_condition=>'P35_FLAG_ANALISTA'
,p_validation_condition2=>'1'
,p_validation_condition_type=>'VAL_OF_ITEM_IN_COND_EQ_COND2'
,p_when_button_pressed=>wwv_flow_api.id(315717907860657995)
,p_associated_item=>wwv_flow_api.id(315712188234658007)
,p_error_display_location=>'INLINE_WITH_FIELD'
);
