 p_id=>wwv_flow_api.id(106437130367298119)
,p_plug_name=>unistr('Tabla: Reporte de Contratos Tur\00EDsticos')
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(36404937346894372)
,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    e.id_empresa, ',
'	e.nombre_solicitante,',
'	e.tipo_cedula,',
'	e.nacional,',
'	e.cedula,',
'	e.razon_social,',
'	e.telefono,',
'	e.correo,',
'	e.id_provincia,',
'	dt.id_declaratoria,',
'	dt.fecha_registro,',
'	dt.tipo_opera_dt,',
'	dt.id_tipodt,',
'	dt.id_categoria,',
'    dt.estadodt,',
'	ct.id_contrato,',
'    ct.fecha_registro as fr_ct,',
'	ct.fecha_caducidad,',
'	ct.estadoct',
'FROM empresa e',
'  INNER JOIN declaratoria_turistica dt ON e.id_empresa = dt.id_empresa ',
'  INNER JOIN contrato_turistico ct ON ct.ID_DECLARATORIA = dt.id_declaratoria',
'  WHERE ct.id_contrato IS NOT NULL'))
,p_plug_source_type=>'NATIVE_IG'
