wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(36498858440894326)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Login'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    -- Usamos un CHAR(1) para verificar la existencia.',
'    v_dummy           CHAR(1);',
'    ',
unistr('    -- Excepci\00F3n controlada para usuario no encontrado o sin permiso local.'),
'    E_USUARIO_SIN_PERMISO EXCEPTION; ',
'    PRAGMA EXCEPTION_INIT(E_USUARIO_SIN_PERMISO, -20001);',
'',
'BEGIN',
'    -- 1. Verificar la existencia del usuario en la tabla local',
'    BEGIN',
'        SELECT ''X''',
'        INTO v_dummy',
'        FROM usuarios_gestion',
unistr('        WHERE UPPER(usuario) = UPPER(:P9999_USERNAME); -- <--- CORRECCI\00D3N APLICADA AQU\00CD'),
'',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            RAISE E_USUARIO_SIN_PERMISO;',
'        WHEN TOO_MANY_ROWS THEN',
'             RAISE E_USUARIO_SIN_PERMISO; ',
'    END;',
'',
unistr('    -- 2. Si el usuario existe, se inicia el proceso de autenticaci\00F3n de APEX.'),
unistr('    -- La funci\00F3n APEX_CUSTOM_AUTH.LOGIN inicia la sesi\00F3n.'),
'    APEX_CUSTOM_AUTH.LOGIN (',
'        p_uname => :P9999_USERNAME,',
'        p_password => :P9999_PASSWORD,',
'        p_session_id => V(''APP_SESSION'')',
'    );',
'',
'EXCEPTION',
'    WHEN E_USUARIO_SIN_PERMISO THEN',
'        RAISE_APPLICATION_ERROR(',
'            -20001, ',
unistr('            ''Acceso denegado. Su usuario no est\00E1 autorizado para esta aplicaci\00F3n.'''),
'        );',
'',
'    WHEN OTHERS THEN',
'        RAISE_APPLICATION_ERROR(',
'            -20002, ',
unistr('            ''Error cr\00EDtico del sistema. Contacte al administrador. '' || SQLERRM'),
'        );',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
